@using sv_36ed616c1f1945599677b891c993b53a

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <div class="d-flex justify-content-between align-items-center mb-1">
            <span class="badge @PriorityClass">@Task.Priority</span>
            <small class="text-muted">@Task.DueDate.ToString("MMM dd")</small>
        </div>
        <div class="d-flex justify-content-between">
            @if (CanMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveLeft">← Move Left</button>
            }
            else
            {
                <span></span>
            }
            @if (CanMoveRight)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveRight">Move Right →</button>
            }
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public TaskItem Task { get; set; } = default!;
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback OnMoveLeft { get; set; }
    [Parameter] public EventCallback OnMoveRight { get; set; }

    private string PriorityClass => Task.Priority switch
    {
        "High" => "bg-danger",
        "Medium" => "bg-warning text-dark",
        "Low" => "bg-success",
        _ => "bg-secondary"
    };
}

@using sv_36ed616c1f1945599677b891c993b53a

<div class="col">
    <div class="card h-100">
        <div class="card-header d-flex justify-content-between align-items-center">
            <h5 class="mb-0">@ColumnName</h5>
            <span class="badge bg-secondary">@Tasks.Count</span>
        </div>
        <div class="card-body overflow-auto" style="max-height: 60vh;">
            @foreach (var task in Tasks)
            {
                <TaskCard Task="task"
                          CanMoveLeft="CanMoveLeft"
                          CanMoveRight="CanMoveRight"
                          OnMoveLeft="() => OnMoveTask.InvokeAsync((task.Id, MoveDirection.Left))"
                          OnMoveRight="() => OnMoveTask.InvokeAsync((task.Id, MoveDirection.Right))" />
            }

            @if (showForm)
            {
                <AddTaskForm DefaultStatus="@ColumnName"
                             OnSave="HandleSave"
                             OnCancel="() => showForm = false" />
            }
        </div>
        <div class="card-footer">
            <button class="btn btn-outline-primary btn-sm w-100" @onclick="() => showForm = true" disabled="@showForm">
                + Add Task
            </button>
        </div>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public string ColumnName { get; set; } = default!;
    [Parameter, EditorRequired] public List<TaskItem> Tasks { get; set; } = new();
    [Parameter] public bool CanMoveLeft { get; set; }
    [Parameter] public bool CanMoveRight { get; set; }
    [Parameter] public EventCallback<(int TaskId, MoveDirection Direction)> OnMoveTask { get; set; }
    [Parameter] public EventCallback<(string Title, string Assignee, string Priority, DateTime DueDate, string Status)> OnAddTask { get; set; }

    private bool showForm;

    private async Task HandleSave((string Title, string Assignee, string Priority, DateTime DueDate) data)
    {
        await OnAddTask.InvokeAsync((data.Title, data.Assignee, data.Priority, data.DueDate, ColumnName));
        showForm = false;
    }

    public enum MoveDirection { Left, Right }
}

@page "/board"
@using sv_36ed616c1f1945599677b891c993b53a
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h3 class="mb-3">Project Board</h3>

@if (loading)
{
    <div class="d-flex justify-content-center py-5">
        <div class="spinner-border" role="status">
            <span class="visually-hidden">Loading…</span>
        </div>
    </div>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger" role="alert">
        <strong>Error loading tasks:</strong> @errorMessage
        <button class="btn btn-outline-danger btn-sm ms-3" @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardSummaryBar Tasks="allTasks" />
    <BoardSearchBar @bind-SearchTerm="searchTerm" />

    <div class="row g-3">
        @foreach (var col in columns)
        {
            var colIndex = Array.IndexOf(columns, col);
            <KanbanColumn ColumnName="@col"
                          Tasks="GetFilteredTasks(col)"
                          CanMoveLeft="colIndex > 0"
                          CanMoveRight="colIndex < columns.Length - 1"
                          OnMoveTask="args => HandleMoveTask(args.TaskId, args.Direction, colIndex)"
                          OnAddTask="HandleAddTask" />
        }
    </div>
}

@code {
    private List<TaskItem> allTasks = new();
    private string searchTerm = string.Empty;
    private bool loading = true;
    private string? errorMessage;

    private static readonly string[] columns = ["To Do", "In Progress", "Done"];

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        loading = true;
        errorMessage = null;

        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var query = allTasks.Where(t => t.Status == status);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            query = query.Where(t => t.Title.Contains(searchTerm, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    private async Task HandleMoveTask(int taskId, KanbanColumn.MoveDirection direction, int currentColIndex)
    {
        var targetIndex = direction == KanbanColumn.MoveDirection.Left
            ? currentColIndex - 1
            : currentColIndex + 1;

        if (targetIndex < 0 || targetIndex >= columns.Length) return;

        var newStatus = columns[targetIndex];
        await TaskService.UpdateTaskStatusAsync(taskId, newStatus);

        var task = allTasks.First(t => t.Id == taskId);
        var index = allTasks.IndexOf(task);
        allTasks[index] = task with { Status = newStatus };
    }

    private async Task HandleAddTask((string Title, string Assignee, string Priority, DateTime DueDate, string Status) data)
    {
        var newTask = await TaskService.CreateTaskAsync(data.Title, data.Assignee, data.Priority, data.DueDate);
        allTasks.Add(newTask with { Status = data.Status });
    }
}

