@using sv_36ed616c1f1945599677b891c993b53a

<div class="card mb-2">
    <div class="card-body p-2">
        <h6 class="card-title mb-1">@Task.Title</h6>
        <p class="card-text mb-1 text-muted small">@Task.Assignee</p>
        <div class="d-flex justify-content-between align-items-center mb-1">
            <span class="badge @PriorityClass">@Task.Priority</span>
            <small class="text-muted">@Task.DueDate.ToString("MMM dd")</small>
        </div>
        <div class="d-flex justify-content-between">
            @if (CanMoveLeft)
            {
                <button class="btn btn-outline-secondary btn-sm" @onclick="OnMoveLeft">← Move Left</button>
